    "reportingPeriodStart": { "type": "string", "format": "date", "description": "Start date of the reporting period" },
    "reportingPeriodEnd": { "type": "string", "format": "date", "description": "End date of the reporting period" },
    "generatedAt": { "type": "string", "format": "date-time", "description": "Timestamp of export generation" },
    "totalFacilities": { "type": "integer", "description": "Count of regulated facilities in the period" },
    "aggregatedEmissions": {
      "type": "object",
      "properties": {
        "totalCo2Emissions": { "type": "number", "description": "City-wide CO2 emissions in metric tons" },
        "totalGhgEmissions": { "type": "number", "description": "City-wide other GHG emissions in metric tons CO2 equivalent" }
      },
      "description": "Aggregated emissions across all facilities"
    },
    "aggregatedOffsets": {
      "type": "object",
      "properties": {
        "totalPurchasedCredits": { "type": "number", "description": "Total offset credits purchased city-wide" },
        "totalReservedCredits": { "type": "number", "description": "Total reserved credits (provisional)" }
      },
