      "type": "object",
      "properties": {
        "netVariance": { "type": "number", "description": "Net municipal variance (includes collapsed rebalanced deficits; positive = overall deficit)" },
        "description": { "type": "string", "default": "Generalized municipal adjustments for remediation variances", "description": "Category description (fixed)" }
      },
      "description": "Collapsed category for rebalanced deficits and other municipal adjustments"
    },
    "overallCompliance": {
      "type": "object",
      "properties": {
        "netCityCompliance": { "type": "number", "description": "City-wide net compliance after variances" },
        "complianceRate": { "type": "number", "minimum": 0, "maximum": 100, "description": "Percentage of facilities in compliance (anonymized)" }
